CustomField.formula:
IF(
  ISPICKVAL(DRC_NBC_Type__c, "Domestic"),

  TotalPrice +
  /* GST logic based on state */
  IF(
     TEXT(Contact.Account.BillingStateCode) = "MH",
    /* CGST + SGST */
    IF(ISBLANK(DRC_NBC_C_GST__c), 0, DRC_NBC_C_GST__c) +
    IF(ISBLANK(DRC_NBC_S_GST__c), 0, DRC_NBC_S_GST__c),
    /* IGST */
    IF(ISBLANK(DRC_NBC_I_GST__c), 0, DRC_NBC_I_GST__c)
  ) +
  /* Other taxes */
  IF(ISBLANK(DRC_NBC_Other_Tax_Amount__c), 0, DRC_NBC_Other_Tax_Amount__c) +
  IF(ISBLANK(DRC_NBC_TCS_Amount__c), 0, DRC_NBC_TCS_Amount__c),

  /* EXPORT case */
  IF(
    ISPICKVAL(DRC_NBC_Type__c, "Export"),
    TotalPrice +
    IF(ISBLANK(DRC_NBC_Other_Tax_Amount__c), 0, DRC_NBC_Other_Tax_Amount__c),

    /* DEFAULT fallback (if type is neither Domestic nor Export) */
    TotalPrice
  )
)
